import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
// import './Table.css';

function Table() {
  const [tableData, setTableData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [debugInfo, setDebugInfo] = useState({});
  const [authChecked, setAuthChecked] = useState(false);
  const navigate = useNavigate();

  const checkAuthAndFetch = async () => {
    setLoading(true);
    setError(null);

    try {
      // Сначала проверяем авторизацию
      const authResponse = await fetch('http://localhost:5000/sings', {
        method: 'HEAD',
        credentials: 'include'
      });

      setAuthChecked(true);

      if (authResponse.status === 401) {
        setError('Unauthorized. Please login first.');
        setTimeout(() => {
          navigate('/login');
        }, 2000);
        return;
      }

      // Если авторизованы, загружаем данные
      const startTime = Date.now();
      const response = await fetch('http://localhost:5000/sings', {
        credentials: 'include'
      });
      const endTime = Date.now();

      const data = await response.json();

      setDebugInfo({
        authStatus: authResponse.status,
        dataStatus: response.status,
        responseTime: `${endTime - startTime}ms`,
        timestamp: new Date().toISOString(),
        url: response.url
      });

      if (response.ok) {
        setTableData(Array.isArray(data) ? data : [data]);
      } else {
        setError(`Error ${response.status}: ${JSON.stringify(data)}`);
        if (response.status === 401) {
          setTimeout(() => navigate('/login'), 1500);
        }
      }
    } catch (error) {
      setError(error.message);
      setDebugInfo(prev => ({...prev, error: error.message}));
      if (error.message.includes('Unauthorized') || error.message.includes('401')) {
        setTimeout(() => navigate('/login'), 1500);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = async () => {
    try {
      // Если есть эндпоинт для логаута
      const response = await fetch('http://localhost:5000/logout', {
        method: 'POST',
        credentials: 'include'
      });

      if (response.ok) {
        navigate('/login');
      }
    } catch (error) {
      // Если нет эндпоинта логаута, просто очищаем и переходим
      navigate('/login');
    }
  };

  const clearData = () => {
    setTableData([]);
    setDebugInfo({});
  };

  useEffect(() => {
    checkAuthAndFetch();
  }, []);

  return (
    <div className="table-container">
      <div className="table-header">
        <h2>Protected Table Data</h2>
        <div className="header-controls">
          <button onClick={() => navigate('/login')} className="back-button">
            Back to Login
          </button>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className="controls">
        <button 
          onClick={checkAuthAndFetch} 
          disabled={loading}
          className="fetch-button"
        >
          {loading ? (
            <>
              <span className="spinner small"></span>
              Loading...
            </>
          ) : 'Refresh Data'}
        </button>

        <button onClick={clearData} className="clear-button">
          Clear Data
        </button>

        <button onClick={() => {
          alert(`Auth checked: ${authChecked}\nCookies: ${document.cookie}`);
        }} className="auth-button">
          Check Auth
        </button>
      </div>

      {error && (
        <div className={`error-message ${error.includes('Unauthorized') ? 'warning' : ''}`}>
          <strong>{error.includes('Unauthorized') ? '⚠️ Warning:' : 'Error:'}</strong> {error}
          {error.includes('Unauthorized') && (
            <button onClick={() => navigate('/login')} className="inline-button">
              Go to Login
            </button>
          )}
        </div>
      )}

      <div className="data-section">
        <h3>Table Data {tableData.length > 0 && `(${tableData.length} rows)`}</h3>
        {tableData.length > 0 ? (
          <div className="table-wrapper">
            <table>
              <thead>
                <tr>
                  {Object.keys(tableData[0]).map(key => (
                    <th key={key}>{key}</th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {tableData.map((row, index) => (
                  <tr key={index}>
                    {Object.values(row).map((value, cellIndex) => (
                      <td key={cellIndex}>
                        {typeof value === 'object' ? JSON.stringify(value) : String(value)}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <div className="empty-state">
            <p>No data available. {!loading && 'Click "Refresh Data" to fetch.'}</p>
          </div>
        )}
      </div>

      <div className="debug-section">
        <h3>Request Information</h3>
        <pre>{JSON.stringify(debugInfo, null, 2)}</pre>
      </div>

      <div className="status-info">
        <div className="status-item">
          <span className="status-label">Authentication:</span>
          <span className={`status-value ${authChecked ? 'success' : 'pending'}`}>
            {authChecked ? '✓ Checked' : '⏳ Pending'}
          </span>
        </div>
        <div className="status-item">
          <span className="status-label">Data loaded:</span>
          <span className={`status-value ${tableData.length > 0 ? 'success' : 'empty'}`}>
            {tableData.length > 0 ? `${tableData.length} items` : 'Empty'}
          </span>
        </div>
        <div className="status-item">
          <span className="status-label">Cookies:</span>
          <span className="status-value">
            {document.cookie ? 'Present' : 'Missing'}
          </span>
        </div>
      </div>
    </div>
  );
}

export default Table;
